const { Manifold, CrossSection, label, setCircularSegments } = api;
setCircularSegments(48);

// Crown band: hollow cylinder r=9, inner r=7.5, h=6
const outerBand = Manifold.cylinder(6, 9, 9, 48);
const innerHole = Manifold.cylinder(7, 7.5, 7.5, 48).translate([0, 0, -0.5]);
const band = outerBand.subtract(innerHole);

// Pointed peaks around the top rim — 8 peaks evenly spaced
// Each peak is a tall thin box with tapered top (approximated as a narrow pyramid using a cone tip)
// Actually use a prism shape: rectangular base, triangular point
// Simplify: use a cube that's tall and narrow, sitting on top of the band
const numPeaks = 8;
const peakH = 8;
const peakW = 2.8;
const peakD = 2.0;
const bandTopZ = 6;
const peakRadius = 8.5; // center of peaks

let peakParts = [];
for (let i = 0; i < numPeaks; i++) {
  const angle = (i * 360) / numPeaks;
  const angleRad = (angle * Math.PI) / 180;
  const px = peakRadius * Math.cos(angleRad);
  const py = peakRadius * Math.sin(angleRad);

  // Peak shape: wider box at base tapering to narrow point
  // Use a hull-ish approach: box at base + narrower box on top
  const peakBase = Manifold.cube([peakW, peakD, peakH * 0.5], true)
    .translate([px, py, bandTopZ + peakH * 0.25]);
  // Top pyramidal part — a cone tip
  const peakTip = Manifold.cylinder(peakH * 0.55, peakW * 0.5, 0.0, 16)
    .translate([px, py, bandTopZ + peakH * 0.5]);

  peakParts.push(peakBase.add(peakTip));
}
const peaks = Manifold.union(peakParts);

// The gold parts: band + peaks
const goldParts = label(band.add(peaks), 'gold');

// Jewels: 6 jewels around the band at z=3 (mid-band height)
// Alternating red, blue, green — 2 of each
const jewelR = 1.3;
const jewelRadius = 9.2; // just proud of band surface
const jewelZ = 3.0;
const numJewels = 6;

let jewelsRed = [];
let jewelsBlue = [];
let jewelsGreen = [];

for (let i = 0; i < numJewels; i++) {
  const angle = (i * 360) / numJewels;
  const angleRad = (angle * Math.PI) / 180;
  const jx = jewelRadius * Math.cos(angleRad);
  const jy = jewelRadius * Math.sin(angleRad);
  const jewel = Manifold.sphere(jewelR, 24).translate([jx, jy, jewelZ]);
  const colorIdx = i % 3;
  if (colorIdx === 0) jewelsRed.push(jewel);
  else if (colorIdx === 1) jewelsBlue.push(jewel);
  else jewelsGreen.push(jewel);
}

const jewelRedGroup = label(Manifold.union(jewelsRed), 'jewelRed');
const jewelBlueGroup = label(Manifold.union(jewelsBlue), 'jewelBlue');
const jewelGreenGroup = label(Manifold.union(jewelsGreen), 'jewelGreen');

return goldParts.add(jewelRedGroup).add(jewelBlueGroup).add(jewelGreenGroup);
